"use strict";parserFactory.register("cclawtranslations.home.blog",()=>new CClawTranslationsParser);class CClawTranslationsParser extends WordpressBaseParser{constructor(){super()}extractTitleImpl(e){return e.querySelector("h1.entry-title").innerText.replace(/( \(LN\))|( ToC)/g,"")}findChapterTitle(e){return e.querySelector("h1.entry-title").innerText.replace(/(\w.*)(?<=Volume \d )/g,"")}removeUnwantedElementsFromContentElement(e){super.removeUnwantedElementsFromContentElement(e),util.removeElements([...e.querySelectorAll("p")].filter(this.hasDiscordOrPatreon))}hasDiscordOrPatreon(e){return 0<[...e.querySelectorAll("a")].map(e=>e.href.toLowerCase()).filter(e=>e.includes("discord")||e.includes("patreon")).length||e.textContent.toLowerCase().includes("patreon")}}